import 'dart:convert';

Package packageFromJson(String str) => Package.fromJson(json.decode(str));

String packageToJson(Package data) => json.encode(data.toJson());

class Package {
    String name;
    String author;
    String homepage;
    String version;
    String license;
    String description;
    List<String> keywords;
    Bugs bugs;
    Repository repository;
    String main;
    String typings;
    Bin bin;
    Engines engines;
    List<String> files;
    Map<String, String> devDependencies;
    Overrides overrides;
    Scripts scripts;
    Browser browser;
    String packageManager;
    Volta volta;

    Package({
        required this.name,
        required this.author,
        required this.homepage,
        required this.version,
        required this.license,
        required this.description,
        required this.keywords,
        required this.bugs,
        required this.repository,
        required this.main,
        required this.typings,
        required this.bin,
        required this.engines,
        required this.files,
        required this.devDependencies,
        required this.overrides,
        required this.scripts,
        required this.browser,
        required this.packageManager,
        required this.volta,
    });

    factory Package.fromJson(Map<String, dynamic> json) => Package(
        name: json["name"],
        author: json["author"],
        homepage: json["homepage"],
        version: json["version"],
        license: json["license"],
        description: json["description"],
        keywords: List<String>.from(json["keywords"].map((x) => x)),
        bugs: Bugs.fromJson(json["bugs"]),
        repository: Repository.fromJson(json["repository"]),
        main: json["main"],
        typings: json["typings"],
        bin: Bin.fromJson(json["bin"]),
        engines: Engines.fromJson(json["engines"]),
        files: List<String>.from(json["files"].map((x) => x)),
        devDependencies: Map.from(json["devDependencies"]).map((k, v) => MapEntry<String, String>(k, v)),
        overrides: Overrides.fromJson(json["overrides"]),
        scripts: Scripts.fromJson(json["scripts"]),
        browser: Browser.fromJson(json["browser"]),
        packageManager: json["packageManager"],
        volta: Volta.fromJson(json["volta"]),
    );

    Map<String, dynamic> toJson() => {
        "name": name,
        "author": author,
        "homepage": homepage,
        "version": version,
        "license": license,
        "description": description,
        "keywords": List<dynamic>.from(keywords.map((x) => x)),
        "bugs": bugs.toJson(),
        "repository": repository.toJson(),
        "main": main,
        "typings": typings,
        "bin": bin.toJson(),
        "engines": engines.toJson(),
        "files": List<dynamic>.from(files.map((x) => x)),
        "devDependencies": Map.from(devDependencies).map((k, v) => MapEntry<String, dynamic>(k, v)),
        "overrides": overrides.toJson(),
        "scripts": scripts.toJson(),
        "browser": browser.toJson(),
        "packageManager": packageManager,
        "volta": volta.toJson(),
    };
}

class Bin {
    String tsc;
    String tsserver;

    Bin({
        required this.tsc,
        required this.tsserver,
    });

    factory Bin.fromJson(Map<String, dynamic> json) => Bin(
        tsc: json["tsc"],
        tsserver: json["tsserver"],
    );

    Map<String, dynamic> toJson() => {
        "tsc": tsc,
        "tsserver": tsserver,
    };
}

